class Solution {
public:
    bool makeStringsEqual(string s, string target) {
        bool hasOneInS = false, hasOneInTarget = false;
        for (char c : s) {
            if (c == '1') {
                hasOneInS = true;
                break;
            }
        }
        for (char c : target) {
            if (c == '1') {
                hasOneInTarget = true;
                break;
            }
        }
        return hasOneInS == hasOneInTarget;
    }
};
```
